import { useState } from "react";
import { useTranslation } from "react-i18next";
import { ArrowLeft, ArrowRight, Loader2, Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import RecipeBasicStep from "./RecipeBasicStep";
import RecipeIngredientsStep from "./RecipeIngredientsStep";
import RecipeStepsStep from "./RecipeStepsStep";
import { RecipeData, Ingredient, RecipeStep, NutritionInfo } from "./RecipeTypes";
import { useCreateRecipe } from "@/hooks/useCreateRecipe";
import { toast } from "sonner";

interface CreateRecipeWizardProps {
  onClose: () => void;
  onSuccess: () => void;
  prefillFromAI?: any;
}

const CreateRecipeWizard = ({ onClose, onSuccess, prefillFromAI }: CreateRecipeWizardProps) => {
  const { t } = useTranslation();
  const createRecipe = useCreateRecipe();

  const [currentStep, setCurrentStep] = useState(0);
  const [coverImage, setCoverImage] = useState<string | null>(prefillFromAI?.image_url || null);
  const [recipeData, setRecipeData] = useState<Partial<RecipeData>>({
    recipe_name: prefillFromAI?.recipe_name || "",
    cook_time: prefillFromAI?.cook_time || undefined,
    difficulty: prefillFromAI?.difficulty || undefined,
    servings: prefillFromAI?.servings || undefined,
  });
  const [ingredients, setIngredients] = useState<Ingredient[]>(
    prefillFromAI?.ingredients?.length
      ? prefillFromAI.ingredients.map((ing: any) => ({
          name: ing.name || "",
          amount: String(ing.amount || ""),
          unit: ing.unit || "",
        }))
      : [{ name: "", amount: "", unit: "" }]
  );
  const [steps, setSteps] = useState<RecipeStep[]>(
    prefillFromAI?.steps?.length
      ? prefillFromAI.steps.map((s: any, i: number) => ({
          order: s.order || i + 1,
          description: s.description || "",
        }))
      : [{ order: 1, description: "" }]
  );
  const [nutrition, setNutrition] = useState<NutritionInfo>({});
  const [introduction, setIntroduction] = useState(prefillFromAI?.introduction || "");

  const STEPS = [
    { key: "basic", title: t("recipe.step.basic", "基本信息") },
    { key: "ingredients", title: t("recipe.step.ingredients", "配料") },
    { key: "steps", title: t("recipe.step.steps", "步骤") },
  ];

  const progress = ((currentStep + 1) / STEPS.length) * 100;

  const validateBasicStep = () => {
    if (!recipeData.recipe_name?.trim()) {
      toast.error(t("recipe.nameRequired", "请输入食谱名称"));
      return false;
    }
    if (!recipeData.cook_time || recipeData.cook_time < 1) {
      toast.error(t("recipe.cookTimeRequired", "请输入烹饪时间"));
      return false;
    }
    if (!recipeData.difficulty) {
      toast.error(t("recipe.difficultyRequired", "请选择难度"));
      return false;
    }
    if (!recipeData.servings || recipeData.servings < 1) {
      toast.error(t("recipe.servingsRequired", "请输入份量"));
      return false;
    }
    return true;
  };

  const validateIngredientsStep = () => {
    const validIngredients = ingredients.filter(i => i.name.trim());
    if (validIngredients.length === 0) {
      toast.error(t("recipe.ingredientsRequired", "请至少添加一种配料"));
      return false;
    }
    return true;
  };

  const validateStepsStep = () => {
    const validSteps = steps.filter(s => s.description.trim());
    if (validSteps.length === 0) {
      toast.error(t("recipe.stepsRequired", "请至少添加一个步骤"));
      return false;
    }
    return true;
  };

  const handleNext = () => {
    if (currentStep === 0 && !validateBasicStep()) return;
    if (currentStep === 1 && !validateIngredientsStep()) return;
    setCurrentStep((prev) => Math.min(prev + 1, STEPS.length - 1));
  };

  const handleBack = () => {
    setCurrentStep((prev) => Math.max(prev - 1, 0));
  };

  const handleSubmit = async () => {
    if (!validateStepsStep()) return;

    const validIngredients = ingredients.filter(i => i.name.trim());
    const validSteps = steps
      .filter(s => s.description.trim())
      .map((s, i) => ({ ...s, order: i + 1 }));

    // Only include nutrition if at least one field has a value
    const hasNutrition = nutrition.calories || nutrition.protein || nutrition.carbs || nutrition.fat;

    try {
      await createRecipe.mutateAsync({
        recipe_name: recipeData.recipe_name!,
        recipe_name_en: prefillFromAI?.recipe_name_en || undefined,
        recipe_name_pt: prefillFromAI?.recipe_name_pt || undefined,
        cook_time: recipeData.cook_time!,
        difficulty: recipeData.difficulty!,
        servings: recipeData.servings!,
        ingredients: validIngredients,
        steps: validSteps,
        cover_image: coverImage,
        nutrition: hasNutrition ? nutrition : undefined,
        introduction: introduction.trim() || undefined,
        introduction_en: prefillFromAI?.introduction_en || undefined,
        introduction_pt: prefillFromAI?.introduction_pt || undefined,
        subtitle: prefillFromAI?.subtitle || undefined,
        subtitle_en: prefillFromAI?.subtitle_en || undefined,
        subtitle_pt: prefillFromAI?.subtitle_pt || undefined,
        ai_recipe_source: prefillFromAI ? prefillFromAI : undefined,
      });
      onSuccess();
    } catch (error) {
      // Error handled in hook
    }
  };

  const renderStepContent = () => {
    switch (currentStep) {
      case 0:
        return (
          <RecipeBasicStep
            data={recipeData}
            coverImage={coverImage}
            nutrition={nutrition}
            introduction={introduction}
            onDataChange={setRecipeData}
            onCoverImageChange={setCoverImage}
            onNutritionChange={setNutrition}
            onIntroductionChange={setIntroduction}
          />
        );
      case 1:
        return (
          <RecipeIngredientsStep
            ingredients={ingredients}
            onChange={setIngredients}
          />
        );
      case 2:
        return (
          <RecipeStepsStep
            steps={steps}
            onChange={setSteps}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="h-full flex flex-col">
      {/* Header */}
      <div className="px-4 py-3 border-b bg-background shrink-0">
        <div className="flex items-center justify-between mb-3">
          <button
            type="button"
            onClick={onClose}
            className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
          <h2 className="font-medium">{t("recipe.createTitle", "创建食谱")}</h2>
          <div className="w-6" /> {/* Spacer */}
        </div>

        {/* Step Progress */}
        <div className="space-y-2">
          <Progress value={progress} className="h-1" />
          <div className="flex justify-between text-xs text-muted-foreground">
            {STEPS.map((step, index) => (
              <span
                key={step.key}
                className={index === currentStep ? "text-primary font-medium" : ""}
              >
                {step.title}
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4">
        {renderStepContent()}
      </div>

      {/* Footer */}
      <div className="px-4 py-3 pb-[max(1rem,env(safe-area-inset-bottom))] border-t bg-background shrink-0">
        <div className="flex gap-3">
          {currentStep > 0 && (
            <Button
              type="button"
              variant="outline"
              onClick={handleBack}
              className="flex-1"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              {t("common.back", "上一步")}
            </Button>
          )}
          
          {currentStep < STEPS.length - 1 ? (
            <Button
              type="button"
              onClick={handleNext}
              className="flex-1"
            >
              {t("common.next", "下一步")}
              <ArrowRight className="h-4 w-4 ml-2" />
            </Button>
          ) : (
            <Button
              type="button"
              onClick={handleSubmit}
              disabled={createRecipe.isPending}
              className="flex-1"
            >
              {createRecipe.isPending ? (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              ) : (
                <Check className="h-4 w-4 mr-2" />
              )}
              {t("recipe.publish", "发布食谱")}
            </Button>
          )}
        </div>
      </div>
    </div>
  );
};

export default CreateRecipeWizard;
